17	#define list_check_data(vm, argc)                       \
18	    if (!be_islist(vm, -1) || be_top(vm) - 1 < argc) {  \
19	        be_return_nil(vm);                              \
20	    }
21	
22	#define list_check_ref(vm)                              \
23	    if (be_refcontains(vm, 1)) {                        \
24	        be_pushstring(vm, "[...]");                     \
25	        be_return(vm);                                  \
26	    }
27	
28	static void list_getindex(bvm *vm, int index)
29	{
30	    if (!be_getindex(vm, index)) {
31	        be_raise(vm, "index_error", "list index out of range");
32	    }
33	}
34	
35	static int m_init(bvm *vm)
36	{
37	    int i, argc = be_top(vm);
38	    if (argc > 1 && be_islist(vm, 2)) {
39	        be_pushvalue(vm, 2);
40	        be_setmember(vm, 1, ".p");
41	    } else {
42	        be_newlist(vm);
43	        be_setmember(vm, 1, ".p");
44	        for (i = 2; i <= argc; ++i) {
45	            be_pushvalue(vm, i);
46	            be_data_push(vm, -2);
47	            be_pop(vm, 1);
48	        }
49	    }
50	    be_return_nil(vm);
51	}
52	
53	static void push_element(bvm *vm)
54	{
55	    be_toescape(vm, -1, 'x'); /* escape string */
56	    be_strconcat(vm, -3);
57	    be_pop(vm, 1);
58	}
59	
60	static int m_tostring(bvm *vm)
61	{
62	    be_getmember(vm, 1, ".p");
63	    list_check_data(vm, 1);
64	    list_check_ref(vm);
65	    be_refpush(vm, 1);
66	    be_pushstring(vm, "[");
67	    be_pushiter(vm, -2);
68	    while (be_iter_hasnext(vm, -3)) {
69	        be_iter_next(vm, -3);
70	        push_element(vm);
71	        if (be_iter_hasnext(vm, -3)) {
72	            be_pushstring(vm, ", ");
73	            be_strconcat(vm, -3);
74	            be_pop(vm, 1);
75	        }
76	    }
77	    be_pop(vm, 1); /* pop iterator */
78	    be_pushstring(vm, "]");
79	    be_strconcat(vm, -2);
80	    be_pop(vm, 1);
81	    be_refpop(vm);
82	    be_return(vm);
83	}
84	
85	static int m_push(bvm *vm)
86	{
87	    be_getmember(vm, 1, ".p");
88	    list_check_data(vm, 2);
89	    be_pushvalue(vm, 2);
90	    be_data_push(vm, -2);
91	    be_return_nil(vm);
92	}
93	
94	static int m_pop(bvm *vm)
95	{
96	    int argc = be_top(vm);
97	    be_getmember(vm, 1, ".p");
98	    list_check_data(vm, 1);
99	    if (argc >= 2) {
100	        be_pushvalue(vm, 2);
101	    } else {
102	        be_pushint(vm, -1);
103	    }
104	    list_getindex(vm, -2);
105	    be_pushvalue(vm, -2);
106	    be_data_remove(vm, -4);
107	    be_pop(vm, 1);
108	    be_return(vm);
109	}
110	
111	static int m_insert(bvm *vm)
112	{
113	    be_getmember(vm, 1, ".p");
114	    list_check_data(vm, 3);
115	    be_pushvalue(vm, 2);
116	    be_pushvalue(vm, 3);
117	    be_data_insert(vm, -3);
118	    be_return_nil(vm);
119	}
120	
121	static int m_remove(bvm *vm)
122	{
123	    be_getmember(vm, 1, ".p");
124	    list_check_data(vm, 2);
125	    be_pushvalue(vm, 2);
126	    be_data_remove(vm, -2);
127	    be_return_nil(vm);
128	}
129	
130	static int item_range(bvm *vm)
131	{
132	    bint lower, upper;
133	    bint size = be_data_size(vm, -1); /* get source list size */
134	    /* get index range */
135	    be_getmember(vm, 2, "__lower__");
136	    lower = be_toint(vm, -1);
137	    be_pop(vm, 1);
138	    be_getmember(vm, 2, "__upper__");
139	    upper = be_toint(vm, -1);
140	    be_pop(vm, 1);
141	    /* protection scope */
142	    upper = upper < size ? upper : size - 1;
143	    lower = lower < 0 ? 0 : lower;
144	    /* construction result list instance */
145	    be_newobject(vm, "list"); /* result list */
146	    be_getmember(vm, 1, ".p"); /* source list */
147	    /* copy elements */
148	    for (; lower <= upper; ++lower) {
149	        be_pushint(vm, lower);
150	        list_getindex(vm, -2);
151	        be_data_push(vm, -4);
152	        be_pop(vm, 2);
153	    }
154	    be_pop(vm, 2);
155	    be_return(vm);
156	}
157	
158	static int item_list(bvm *vm)
159	{
160	    int i, srcsize, idxsize;
161	    be_getmember(vm, 2, ".p"); /* get index list */
162	    srcsize = be_data_size(vm, -2); /* get source list size */
163	    idxsize = be_data_size(vm, -1); /* get index list size */
164	    /* construction result list instance */
165	    be_newobject(vm, "list"); /* result list */
166	    be_getmember(vm, 1, ".p"); /* source list */
167	    /* copy elements */
168	    for (i = 0; i < idxsize; ++i) {
169	        be_pushint(vm, i);
170	        be_getindex(vm, -5);
171	        if (be_isint(vm, -1)) {
172	            int idx = be_toindex(vm, -1);
173	            if (idx >= 0 && idx < srcsize) {
174	                be_getindex(vm, -3);
175	            } else {
176	                be_pushnil(vm);
177	            }
178	        } else {
179	            be_pushnil(vm);
180	        }
181	        be_data_push(vm, -5);
182	        be_pop(vm, 3);
183	    }
184	    be_pop(vm, 2);
185	    be_return(vm);
186	}
187	
188	static int m_item(bvm *vm)
189	{
190	    be_getmember(vm, 1, ".p");
191	    list_check_data(vm, 2);
192	    if (be_isint(vm, 2)) {
193	        be_pushvalue(vm, 2);
194	        list_getindex(vm, -2);
195	        be_return(vm);
196	    }
197	    if (be_isinstance(vm, 2)) {
198	        const char *cname = be_classname(vm, 2);
199	        if (!strcmp(cname, "range")) {
200	            return item_range(vm);
201	        }
202	        if (!strcmp(cname, "list")) {
203	            return item_list(vm);
204	        }
205	    }
206	    be_raise(vm, "index_error", "list index out of range");
207	    be_return_nil(vm);
208	}
209	
210	static int m_find(bvm *vm)
211	{
212	    be_getmember(vm, 1, ".p");
213	    list_check_data(vm, 2);
214	    if (be_isint(vm, 2)) {
215	        be_pushvalue(vm, 2);
216	        if (be_getindex(vm, -2)) {
217	            be_return(vm);
218	        }
219	    }
220	    be_return_nil(vm);
221	}
222	
223	static int m_setitem(bvm *vm)
224	{
225	    be_getmember(vm, 1, ".p");
226	    list_check_data(vm, 3);
227	    be_pushvalue(vm, 2);
228	    be_pushvalue(vm, 3);
229	    if (!be_setindex(vm, -3)) {
230	        be_raise(vm, "index_error", "list assignment index out of range");
231	    }
232	    be_return_nil(vm);
233	}
234	
235	static int m_size(bvm *vm)
236	{
237	    be_getmember(vm, 1, ".p");
238	    list_check_data(vm, 1);
239	    be_pushint(vm, be_data_size(vm, -1));
240	    be_return(vm);
241	}
242	
243	static int m_resize(bvm *vm)
244	{
245	    be_getmember(vm, 1, ".p");
246	    list_check_data(vm, 2);
247	    be_pushvalue(vm, 2);
248	    be_data_resize(vm, -2);
249	    be_return_nil(vm);
250	}
251	
252	static int m_clear(bvm *vm)
253	{
254	    be_getmember(vm, 1, ".p");
255	    list_check_data(vm, 1);
256	    be_pushint(vm, 0);
257	    be_data_resize(vm, -2);
258	    be_return_nil(vm);
259	}
260	
261	static int iter_closure(bvm *vm)
262	{
263	    /* for better performance, we operate the upvalues
264	     * directly without using by the stack. */
265	    bntvclos *func = var_toobj(vm->cf->func);
266	    bvalue *uv0 = be_ntvclos_upval(func, 0)->value; /* list value */
267	    bvalue *uv1 = be_ntvclos_upval(func, 1)->value; /* iter value */
268	    bvalue *next = cast(bvalue*, var_toobj(uv1)) + 1;
269	    blist *list = var_toobj(uv0);
270	    if (next >= be_list_end(list)) {
271	        be_stop_iteration(vm);
272	    }
273	    var_toobj(uv1) = next; /* set upvale[1] (iter value) */
274	    /* push next value to top */
275	    var_setval(vm->top, next);
276	    be_incrtop(vm);
277	    be_return(vm);
278	}
279	
280	static int m_iter(bvm *vm)
281	{
282	    be_pushntvclosure(vm, iter_closure, 2);
283	    be_getmember(vm, 1, ".p");
284	    be_setupval(vm, -2, 0);
285	    be_pushiter(vm, -1);
286	    be_setupval(vm, -3, 1);
287	    be_pop(vm, 2);
288	    be_return(vm);
289	}
290	
291	static int m_connect(bvm *vm)
292	{
293	    int argc = be_top(vm);
294	    if (argc >= 2) {
295	        be_getmember(vm, 1, ".p");
296	        be_pushvalue(vm, 2);
297	        be_data_push(vm, -2);
298	        be_pop(vm, argc + 1);
299	    }
300	    be_return(vm); /* return self */
301	}
302	
303	static int m_merge(bvm *vm)
304	{
305	    int argc = be_top(vm);
306	    if (argc >= 2) {
307	        be_newobject(vm, "list"); /* stack contains instance and .p */
308	        be_getmember(vm, 1, ".p");
309	        be_data_merge(vm, -2);
310	        be_getmember(vm, 2, ".p");
311	        if (!be_islist(vm, -1)) {
312	            be_raise(vm, "type_error", "operand must be a list");
313	        }
314	        be_data_merge(vm, -3);
315	        be_pop(vm, 3);
316	    }
317	    be_return(vm); /* return self */
318	}
319	
320	static void connect(bvm *vm, bvalue *begin, bvalue *end)
321	{
322	    size_t l0 = be_strlen(vm, -1), len = l0;
323	    char *buf, *p;
324	    bvalue *it;
325	    for (it = begin; it < end; ++it) {
326	        len += str_len(var_tostr(it));
327	    }
328	    buf = be_pushbuffer(vm, len);
329	    memcpy(buf, be_tostring(vm, -2), l0);
330	    p = buf + l0;
331	    for (it = begin; it < end; ++it) {
332	        bstring *s = var_tostr(it);
333	        size_t l = str_len(s);
334	        memcpy(p, str(s), l);
335	        p += l;
336	    }
337	    be_pushstring(vm, buf);
338	    be_moveto(vm, -1, -3);
339	    be_pop(vm, 2);
340	}
341	
342	static void list_concat(bvm *vm, blist *list)
343	{
344	    bvalue *it, *begin = be_list_data(list);
345	    bvalue *end = be_list_end(list);
346	    be_pushstring(vm, ""); /* push a empty string */
347	    for (it = begin; it < end;) {
348	        for (; it < end && var_isstr(it); ++it);
349	        connect(vm, begin, it); /* connect string list */
350	        if (it < end) {
351	            /* connect other value */
352	            var_setval(vm->top, it);
353	            be_incrtop(vm);
354	            be_val2str(vm, -1);
355	            be_strconcat(vm, -2);
356	            be_pop(vm, 1);
357	            begin = ++it;
358	        }
359	    }
360	}
361	
362	static int m_concat(bvm *vm)
363	{
364	    bvalue *value;
365	    be_getmember(vm, 1, ".p");
366	    list_check_data(vm, 1);
367	    value = be_indexof(vm, -1);
368	    list_concat(vm, var_toobj(value));
369	    be_return(vm);
370	}
371	
372	static int m_reverse(bvm *vm)
373	{
374	    int top = be_top(vm);
375	    be_getmember(vm, 1, ".p");
376	    list_check_data(vm, 1);
377	    be_data_reverse(vm, -1);
378	    be_pop(vm, top);
379	    be_return(vm);
380	}
381	
382	static int m_copy(bvm *vm)
383	{
384	    be_getmember(vm, 1, ".p");
385	    list_check_data(vm, 1);
386	    be_getbuiltin(vm, "list");
387	    be_copy(vm, -2);
388	    be_call(vm, 1);
389	    be_pop(vm, 1);
390	    be_return(vm);
391	}
392	
393	static int list_equal(bvm *vm, bbool iseq)
394	{
395	    int i, j, res;
396	    bbool (*eqfunc)(bvm*) = iseq ? be_iseq : be_isneq;
397	    be_getmember(vm, 1, ".p");
398	    be_getmember(vm, 2, ".p");
399	    i = be_data_size(vm, -2);
400	    j = be_data_size(vm, -1);
401	    if (i == j) {
402	        res = iseq;
403	        for (i = 0; res == iseq && i < j; ++i) {
404	            be_pushint(vm, i);
405	            be_getindex(vm, -3);
406	            be_pushint(vm, i);
407	            be_getindex(vm, -4);
408	            be_remove(vm, -2);
409	            res = eqfunc(vm);
410	            be_pop(vm, 3);
411	        }
412	    } else {
413	        res = !iseq;
414	    }
415	    be_pushbool(vm, res);
416	    be_return(vm);
417	}
418	
419	static int m_equal(bvm *vm)
420	{
421	    return list_equal(vm, btrue);
422	}
423	
424	static int m_nequal(bvm *vm)
425	{
426	    return list_equal(vm, bfalse);
427	}
428	
429	#if !BE_USE_PRECOMPILED_OBJECT
430	void be_load_listlib(bvm *vm)
431	{
432	    static const bnfuncinfo members[] = {
433	        { ".p", NULL },
434	        { "init", m_init },
435	        { "tostring", m_tostring },
436	        { "push", m_push },
437	        { "pop", m_pop },
438	        { "insert", m_insert },
439	        { "remove", m_remove },
440	        { "item", m_item },
441	        { "find", m_find },
442	        { "setitem", m_setitem },
443	        { "size", m_size },
444	        { "resize", m_resize },
445	        { "clear", m_clear },
446	        { "iter", m_iter },
447	        { "concat", m_concat },
448	        { "reverse", m_reverse },
449	        { "copy", m_copy },
450	        { "..", m_connect },
451	        { "+", m_merge },
452	        { "==", m_equal },
453	        { "!=", m_nequal },
454	        { NULL, NULL }
455	    };
456	    be_regclass(vm, "list", members);
457	}
458	#else
459	/* @const_object_info_begin
460	class be_class_list (scope: global, name: list) {
461	    .p, var
462	    init, func(m_init)
463	    tostring, func(m_tostring)
464	    push, func(m_push)
465	    pop, func(m_pop)
466	    insert, func(m_insert)
467	    remove, func(m_remove)
468	    item, func(m_item)
469	    find, func(m_find)
470	    setitem, func(m_setitem)
471	    size, func(m_size)
472	    resize, func(m_resize)
473	    clear, func(m_clear)
474	    iter, func(m_iter)
475	    concat, func(m_concat)
476	    reverse, func(m_reverse)
477	    copy, func(m_copy)
478	    .., func(m_connect)
479	    +, func(m_merge)
480	    ==, func(m_equal)
481	    !=, func(m_nequal)
482	}
483	@const_object_info_end */
484	#include "../generate/be_fixed_be_class_list.h"
485	#endif
